  1→import { useRef, useCallback, useMemo } from 'react';
  2→import { getStarColor, getStarRadius, simpleHash } from '../utils/starUtils';
  3→
  4→// ── Constants ──────────────────────────────────────────────────────────
  5→const MAX_SPEED = 1.75;
  6→const ACCEL = 0.03;
  7→const BRAKE = 0.04;
  8→const FRICTION = 0.995;
  9→const YAW_RATE = 0.009;
 10→const PITCH_RATE = 0.006;
 11→const PITCH_MAX = (89 * Math.PI) / 180; // 89° in radians
 12→const MIN_VIEW_Z = 0.5;
 13→const SPAWN_DIST = 800;
 14→const RECYCLE_Z = 1200;
 15→const SORT_INTERVAL = 5;
 16→const TARGET_DIST_MAX = 150;
 17→const TARGET_Z_MIN = 2;
 18→const TWO_PI = Math.PI * 2;
 19→
 20→// ── Docking constants ─────────────────────────────────────────────────
 21→const DOCKING_THRESHOLD_Z = 18;
 22→const DOCKING_CENTER_MAX = 50;
 23→const MAGNET_THRESHOLD_Z = 80;
 24→const MAGNET_STRENGTH = 0.015;
 25→const DOCK_ACCEL = 0.08;
 26→const DOCK_MAX_SPEED = 1.5;
 27→
 28→/** Max viewZ at which labels start fading in */
 29→export const LABEL_Z_MAX = 800;
 30→
 31→/** Export docking thresholds for external use */
 32→export { MAGNET_THRESHOLD_Z };
 33→
 34→/** Parse "#5f92ff" → { r, g, b } */
 35→const parseHex = (hex) => ({
 36→    r: parseInt(hex.slice(1, 3), 16),
 37→    g: parseInt(hex.slice(3, 5), 16),
 38→    b: parseInt(hex.slice(5, 7), 16),
 39→});
 40→
 41→/** Seeded pseudo-random from integer seed */
 42→const seededRandom = (seed) => {
 43→    let s = seed | 0;
 44→    return () => {
 45→        s = (s * 1664525 + 1013904223) | 0;
 46→        return ((s >>> 0) / 4294967296);
 47→    };
 48→};
 49→
 50→/** Get forward direction vector from yaw + pitch */
 51→const getForwardVector = (yaw, pitch) => ({
 52→    x: Math.sin(yaw) * Math.cos(pitch),
 53→    y: Math.sin(pitch),
 54→    z: Math.cos(yaw) * Math.cos(pitch),
 55→});
 56→
 57→const useRocketMode = () => {
 58→    const isActiveRef = useRef(false);
 59→    const camPosRef = useRef({ x: 0, y: 0, z: 0 });
 60→    const yawRef = useRef(0);
 61→    const pitchRef = useRef(0);
 62→    const velocityRef = useRef(0);
 63→    const starsRef = useRef([]);
 64→    const sortedIndicesRef = useRef([]);
 65→    const keysRef = useRef({ w: false, s: false, a: false, d: false, q: false, e: false });
 66→    const targetIndexRef = useRef(-1);
 67→    const frameRef = useRef(0);
 68→    const layerRef = useRef(null);
 69→    const rafRef = useRef(null);
 70→    const stageSizeRef = useRef({ width: 0, height: 0 });
 71→    const onKeyDownRef = useRef(null);
 72→    const onKeyUpRef = useRef(null);
 73→
 74→    // ── Docking refs ──────────────────────────────────────────────────
 75→    const dockingStateRef = useRef('none'); // 'none' | 'magnet' | 'approaching' | 'flash' | 'done'
 76→    const dockingTargetIdxRef = useRef(-1);
 77→    const dockingProgressRef = useRef(0);
 78→    const dockingStartTimeRef = useRef(0);
 79→    const dockingCallbackRef = useRef(null);
 80→    const autoDockCbRef = useRef(null); // persistent auto-dock callback, survives manual docking
 81→    const inputFrozenRef = useRef(false);
 82→    const dockingStarScaleRef = useRef(1);
 83→    const dockCooldownRef = useRef(0); // timestamp — suppress auto-dock until this time
 84→    const galaxyCenterRef = useRef({ x: 0, y: 0 });
 85→
 86→    const sortStars = useCallback(() => {
 87→        const stars = starsRef.current;
 88→        const indices = sortedIndicesRef.current;
 89→        // Insertion sort — fast for nearly-sorted arrays, sort by viewZ descending (far first)
 90→        for (let i = 1; i < indices.length; i++) {
 91→            const key = indices[i];
 92→            let j = i - 1;
 93→            while (j >= 0 && stars[indices[j]].viewZ < stars[key].viewZ) {
 94→                indices[j + 1] = indices[j];
 95→                j--;
 96→            }
 97→            indices[j + 1] = key;
 98→        }
 99→    }, []);
100→
101→    const tick = useCallback(() => {
102→        if (!isActiveRef.current) return;
103→
104→        const keys = keysRef.current;
105→        const cam = camPosRef.current;
106→        const stars = starsRef.current;
107→        const size = stageSizeRef.current;
108→        const dockState = dockingStateRef.current;
109→
110→        // ── Input processing (frozen during docking) ──────────────────
111→        if (!inputFrozenRef.current) {
112→            // ── Yaw (A/D) ─────────────────────────────────────────────
113→            if (keys.a) yawRef.current -= YAW_RATE;
114→            if (keys.d) yawRef.current += YAW_RATE;
115→
116→            // ── Pitch (Q/E), clamped ──────────────────────────────────
117→            if (keys.q) pitchRef.current = Math.min(pitchRef.current + PITCH_RATE, PITCH_MAX);
118→            if (keys.e) pitchRef.current = Math.max(pitchRef.current - PITCH_RATE, -PITCH_MAX);
119→
120→            // ── Velocity ──────────────────────────────────────────────
121→            if (keys.w) {
122→                velocityRef.current = Math.min(velocityRef.current + ACCEL, MAX_SPEED);
123→            } else if (keys.s) {
124→                velocityRef.current = Math.max(velocityRef.current - BRAKE, 0);
125→            } else {
126→                velocityRef.current *= FRICTION;
127→                if (velocityRef.current < 0.01) velocityRef.current = 0;
128→            }
129→        }
130→
131→        // ── Magnetic pull (auto-aim toward docking target) ────────────
132→        if (dockState === 'magnet') {
133→            const tidx = dockingTargetIdxRef.current;
134→            if (tidx >= 0 && tidx < stars.length) {
135→                const target = stars[tidx];
136→                const relX = target.worldX - cam.x;
137→                const relY = target.worldY - cam.y;
138→                const relZ = target.worldZ - cam.z;
139→                const dist3D = Math.sqrt(relX * relX + relY * relY + relZ * relZ);
140→                if (dist3D > 0.01) {
141→                    const desiredYaw = Math.atan2(relX, relZ);
142→                    const desiredPitch = Math.asin(Math.max(-1, Math.min(1, relY / dist3D)));
143→                    // Proximity factor: 0 at MAGNET_THRESHOLD_Z, 1 at DOCKING_THRESHOLD_Z
144→                    const proximityFactor = Math.max(0, Math.min(1,
145→                        (MAGNET_THRESHOLD_Z - target.viewZ) / (MAGNET_THRESHOLD_Z - DOCKING_THRESHOLD_Z)
146→                    ));
147→                    const lerpFactor = MAGNET_STRENGTH * (0.3 + proximityFactor * 0.7);
148→                    // Normalize yaw difference to [-PI, PI]
149→                    let yawDiff = desiredYaw - yawRef.current;
150→                    while (yawDiff > Math.PI) yawDiff -= TWO_PI;
151→                    while (yawDiff < -Math.PI) yawDiff += TWO_PI;
152→                    yawRef.current += yawDiff * lerpFactor;
153→                    pitchRef.current += (desiredPitch - pitchRef.current) * lerpFactor;
154→                    pitchRef.current = Math.max(-PITCH_MAX, Math.min(PITCH_MAX, pitchRef.current));
155→                }
156→                // Disengage if target drifts beyond magnet zone
157→                if (target.viewZ > MAGNET_THRESHOLD_Z * 1.2 || target.viewZ < TARGET_Z_MIN) {
158→                    dockingStateRef.current = 'none';
159→                    dockingTargetIdxRef.current = -1;
160→                    dockCooldownRef.current = performance.now() + 500;
161→                }
162→            }
163→        }
164→
165→        // ── Docking animation sequence ────────────────────────────────
166→        if (dockState === 'approaching' || dockState === 'flash') {
167→            const elapsed = performance.now() - dockingStartTimeRef.current;
168→            const tidx = dockingTargetIdxRef.current;
169→            const target = tidx >= 0 && tidx < stars.length ? stars[tidx] : null;
170→
171→            if (elapsed < 800 && target) {
172→                // Phase 1: Auto-approach (0-800ms)
173→                const relX = target.worldX - cam.x;
174→                const relY = target.worldY - cam.y;
175→                const relZ = target.worldZ - cam.z;
176→                const dist3D = Math.sqrt(relX * relX + relY * relY + relZ * relZ);
177→                if (dist3D > 0.01) {
178→                    const desiredYaw = Math.atan2(relX, relZ);
179→                    const desiredPitch = Math.asin(Math.max(-1, Math.min(1, relY / dist3D)));
180→                    let yawDiff = desiredYaw - yawRef.current;
181→                    while (yawDiff > Math.PI) yawDiff -= TWO_PI;
182→                    while (yawDiff < -Math.PI) yawDiff += TWO_PI;
183→                    yawRef.current += yawDiff * 0.12;
184→                    pitchRef.current += (desiredPitch - pitchRef.current) * 0.12;
185→                    pitchRef.current = Math.max(-PITCH_MAX, Math.min(PITCH_MAX, pitchRef.current));
186→                }
187→                velocityRef.current = Math.min(velocityRef.current + DOCK_ACCEL, DOCK_MAX_SPEED);
188→                // Quadratic ease-in scale: 1 → 9
189→                const t1 = elapsed / 800;
190→                dockingStarScaleRef.current = 1 + 8 * t1 * t1;
191→                dockingProgressRef.current = t1 * 0.6;
192→            } else if (elapsed < 1200 && target) {
193→                // Phase 2: Star explosion (800-1200ms)
194→                velocityRef.current *= 0.9;
195→                const t2 = (elapsed - 800) / 400;
196→                // Ease-out scale: 9 → 50
197→                const easeOut = 1 - (1 - t2) * (1 - t2);
198→                dockingStarScaleRef.current = 9 + 41 * easeOut;
199→                dockingProgressRef.current = 0.6 + t2 * 0.3;
200→            } else if (elapsed < 1700) {
201→                // Phase 3: White flash (1200-1700ms)
202→                velocityRef.current = 0;
203→                dockingStateRef.current = 'flash';
204→                const t3 = (elapsed - 1200) / 500;
205→                dockingProgressRef.current = 0.9 + t3 * 0.1;
206→            } else {
207→                // Done — stop loop immediately, then trigger callback exactly once
208→                isActiveRef.current = false;
209→                if (rafRef.current) { cancelAnimationFrame(rafRef.current); rafRef.current = null; }
210→                dockingStateRef.current = 'done';
211→                dockingProgressRef.current = 1;
212→                const cb = dockingCallbackRef.current;
213→                dockingCallbackRef.current = null;
214→                if (cb) cb();
215→                // Restore persistent auto-dock callback for next session
216→                if (autoDockCbRef.current) {
217→                    dockingCallbackRef.current = autoDockCbRef.current;
218→                }
219→                return; // do not reschedule
220→            }
221→        }
222→
223→        const yaw = yawRef.current;
224→        const pitch = pitchRef.current;
225→        const velocity = velocityRef.current;
226→
227→        // ── Position (move along forward vector) ─────────────────────
228→        const fwd = getForwardVector(yaw, pitch);
229→        cam.x += fwd.x * velocity;
230→        cam.y += fwd.y * velocity;
231→        cam.z += fwd.z * velocity;
232→
233→        // ── Pre-compute trig for view transform ──────────────────────
234→        const cosYaw = Math.cos(-yaw);
235→        const sinYaw = Math.sin(-yaw);
236→        const cosPitch = Math.cos(pitch);
237→        const sinPitch = Math.sin(pitch);
238→
239→        // ── View transform + recycling ───────────────────────────────
240→        const dockingActive = dockState !== 'none';
241→        const protectedIdx = dockingTargetIdxRef.current;
242→        for (let i = 0; i < stars.length; i++) {
243→            const star = stars[i];
244→
245→            // Translate to camera-relative
246→            const relX = star.worldX - cam.x;
247→            const relY = star.worldY - cam.y;
248→            const relZ = star.worldZ - cam.z;
249→
250→            // Yaw rotation (around Y axis)
251→            const rotX1 = relX * cosYaw + relZ * sinYaw;
252→            const rotZ1 = -relX * sinYaw + relZ * cosYaw;
253→
254→            // Pitch rotation (around X axis)
255→            const rotY2 = relY * cosPitch - rotZ1 * sinPitch;
256→            const viewZ = relY * sinPitch + rotZ1 * cosPitch;
257→
258→            // Cache on star for renderer
259→            star._rotX1 = rotX1;
260→            star._rotY2 = rotY2;
261→            star.viewZ = viewZ;
262→
263→            // Recycle stars that are behind camera or too far
264→            // Skip recycling for the docking target star
265→            if ((viewZ < MIN_VIEW_Z || viewZ > RECYCLE_Z) && !(dockingActive && i === protectedIdx)) {
266→                // Respawn ahead of camera using forward vector + random spread
267→                const dist = SPAWN_DIST * (0.5 + Math.random() * 0.5);
268→                const spreadX = (Math.random() - 0.5) * 2000;
269→                const spreadY = (Math.random() - 0.5) * 2000;
270→                star.worldX = cam.x + fwd.x * dist + spreadX;
271→                star.worldY = cam.y + fwd.y * dist + spreadY;
272→                star.worldZ = cam.z + fwd.z * dist + (Math.random() - 0.5) * 1000;
273→
274→                // Recompute view-space for the recycled position
275→                const rX = star.worldX - cam.x;
276→                const rY = star.worldY - cam.y;
277→                const rZ = star.worldZ - cam.z;
278→                const rX1 = rX * cosYaw + rZ * sinYaw;
279→                const rZ1 = -rX * sinYaw + rZ * cosYaw;
280→                star._rotX1 = rX1;
281→                star._rotY2 = rY * cosPitch - rZ1 * sinPitch;
282→                star.viewZ = rY * sinPitch + rZ1 * cosPitch;
283→            }
284→        }
285→
286→        // ── Sort (every N frames) ────────────────────────────────────
287→        frameRef.current++;
288→        if (frameRef.current % SORT_INTERVAL === 0) {
289→            sortStars();
290→        }
291→
292→        // ── Target detection ─────────────────────────────────────────
293→        const cx = size.width / 2;
294→        const cy = size.height / 2;
295→        const focalLength = size.width * 0.6;
296→        let bestIdx = -1;
297→        let bestDist = TARGET_DIST_MAX;
298→
299→        for (let i = 0; i < stars.length; i++) {
300→            const star = stars[i];
301→            if (star.viewZ < TARGET_Z_MIN) continue;
302→            const projX = cx + (star._rotX1 / star.viewZ) * focalLength;
303→            const projY = cy - (star._rotY2 / star.viewZ) * focalLength;
304→            const dx = projX - cx;
305→            const dy = projY - cy;
306→            const dist = Math.sqrt(dx * dx + dy * dy);
307→            if (dist < bestDist) {
308→                bestDist = dist;
309→                bestIdx = i;
310→            }
311→        }
312→        targetIndexRef.current = bestIdx;
313→
314→        // ── Docking detection ─────────────────────────────────────────
315→        // Read live ref (not stale snapshot) to respect triggerDocking() calls from user input
316→        const cooldownActive = performance.now() < dockCooldownRef.current;
317→        if (dockingStateRef.current === 'none' && bestIdx >= 0 && !cooldownActive) {
318→            const targetStar = stars[bestIdx];
319→            const viewZ = targetStar.viewZ;
320→            if (viewZ < DOCKING_THRESHOLD_Z && bestDist < DOCKING_CENTER_MAX) {
321→                // Close enough and centered — auto-dock
322→                dockingStateRef.current = 'approaching';
323→                dockingTargetIdxRef.current = bestIdx;
324→                dockingStartTimeRef.current = performance.now();
325→                dockingProgressRef.current = 0;
326→                dockingStarScaleRef.current = 1;
327→                inputFrozenRef.current = true;
328→            } else if (viewZ < MAGNET_THRESHOLD_Z && viewZ > DOCKING_THRESHOLD_Z) {
329→                // In magnet zone — engage gentle pull
330→                dockingStateRef.current = 'magnet';
331→                dockingTargetIdxRef.current = bestIdx;
332→            }
333→        }
334→        // Disengage magnet if best target changes
335→        if (dockingStateRef.current === 'magnet' && bestIdx !== dockingTargetIdxRef.current) {
336→            dockingStateRef.current = 'none';
337→            dockingTargetIdxRef.current = -1;
338→            dockCooldownRef.current = performance.now() + 500; // brief cooldown after target switch
339→        }
340→        // Transition magnet → approaching when within docking threshold and centered
341→        if (dockingStateRef.current === 'magnet') {
342→            const tidx = dockingTargetIdxRef.current;
343→            if (tidx >= 0 && tidx < stars.length) {
344→                const mTarget = stars[tidx];
345→                if (!cooldownActive && mTarget.viewZ < DOCKING_THRESHOLD_Z && mTarget.viewZ > TARGET_Z_MIN) {
346→                    const mProjX = cx + (mTarget._rotX1 / mTarget.viewZ) * focalLength;
347→                    const mProjY = cy - (mTarget._rotY2 / mTarget.viewZ) * focalLength;
348→                    const mDist = Math.sqrt((mProjX - cx) ** 2 + (mProjY - cy) ** 2);
349→                    if (mDist < DOCKING_CENTER_MAX) {
350→                        dockingStateRef.current = 'approaching';
351→                        dockingStartTimeRef.current = performance.now();
352→                        dockingProgressRef.current = 0;
353→                        dockingStarScaleRef.current = 1;
354→                        inputFrozenRef.current = true;
355→                    }
356→                }
357→            }
358→        }
359→
360→        // ── Redraw ───────────────────────────────────────────────────
361→        if (layerRef.current) {
362→            layerRef.current.batchDraw();
363→        }
364→
365→        rafRef.current = requestAnimationFrame(tick);
366→    }, [sortStars]);
367→
368→    const enter = useCallback((galaxyPosts, galaxyCenter, stageSize) => {
369→        // Clean up any existing loop/listeners before re-entering
370→        isActiveRef.current = false;
371→        if (rafRef.current) { cancelAnimationFrame(rafRef.current); rafRef.current = null; }
372→        if (onKeyDownRef.current) {
373→            window.removeEventListener('keydown', onKeyDownRef.current);
374→            window.removeEventListener('keyup', onKeyUpRef.current);
375→            onKeyDownRef.current = null; onKeyUpRef.current = null;
376→        }
377→
378→        stageSizeRef.current = stageSize;
379→        camPosRef.current = { x: galaxyCenter.x, y: galaxyCenter.y, z: 0 };
380→        galaxyCenterRef.current = { x: galaxyCenter.x, y: galaxyCenter.y };
381→        yawRef.current = 0;
382→        pitchRef.current = 0;
383→        velocityRef.current = 0;
384→        frameRef.current = 0;
385→        targetIndexRef.current = -1;
386→
387→        // Reset docking state
388→        dockingStateRef.current = 'none';
389→        dockingTargetIdxRef.current = -1;
390→        dockingProgressRef.current = 0;
391→        dockingStarScaleRef.current = 1;
392→        inputFrozenRef.current = false;
393→        dockCooldownRef.current = 0;
394→
395→        // Build star array from posts — distributed in 3D volume
396→        const stars = [];
397→        for (let i = 0; i < galaxyPosts.length; i++) {
398→            const post = galaxyPosts[i];
399→            const uid = post.users?.id ?? post.user_id;
400→            const likeCount = post.like_count != null
401→                ? post.like_count
402→                : (Array.isArray(post.likes) && post.likes[0]?.count != null
403→                    ? post.likes[0].count : 0);
404→            const color = getStarColor(uid);
405→            const rng = seededRandom(simpleHash(post.id || String(i)));
406→            // Always consume two RNG calls for X/Y so worldZ gets a consistent 3rd draw
407→            const rngX = rng();
408→            const rngY = rng();
409→            stars.push({
410→                postId: post.id,
411→                worldX: post.universe_x ?? post.display_x ?? galaxyCenter.x + (rngX - 0.5) * 2000,
412→                worldY: post.universe_y ?? post.display_y ?? galaxyCenter.y + (rngY - 0.5) * 2000,
413→                worldZ: (rng() - 0.5) * SPAWN_DIST * 2, // ±SPAWN_DIST from camera z=0
414→                viewZ: 0,
415→                _rotX1: 0,
416→                _rotY2: 0,
417→                color,
418→                colorRgb: parseHex(color),
419→                radius: getStarRadius(likeCount),
420→                title: post.title || 'Untitled',
421→                authorName: post.users?.name || post.user_name || 'Anonymous',
422→                post,
423→            });
424→        }
425→
426→        starsRef.current = stars;
427→
428→        // Build sorted indices (far → near by viewZ, will be sorted properly on first tick)
429→        const indices = new Array(stars.length);
430→        for (let i = 0; i < stars.length; i++) indices[i] = i;
431→        sortedIndicesRef.current = indices;
432→
433→        // Key listeners
434→        const onKeyDown = (e) => {
435→            const key = e.key.toLowerCase();
436→            if (key === 'w') keysRef.current.w = true;
437→            if (key === 's') keysRef.current.s = true;
438→            if (key === 'a' || key === 'arrowleft') keysRef.current.a = true;
439→            if (key === 'd' || key === 'arrowright') keysRef.current.d = true;
440→            if (key === 'q' || key === 'arrowup') keysRef.current.q = true;
441→            if (key === 'e' || key === 'arrowdown') keysRef.current.e = true;
442→        };
443→        const onKeyUp = (e) => {
444→            const key = e.key.toLowerCase();
445→            if (key === 'w') keysRef.current.w = false;
446→            if (key === 's') keysRef.current.s = false;
447→            if (key === 'a' || key === 'arrowleft') keysRef.current.a = false;
448→            if (key === 'd' || key === 'arrowright') keysRef.current.d = false;
449→            if (key === 'q' || key === 'arrowup') keysRef.current.q = false;
450→            if (key === 'e' || key === 'arrowdown') keysRef.current.e = false;
451→        };
452→
453→        onKeyDownRef.current = onKeyDown;
454→        onKeyUpRef.current = onKeyUp;
455→        window.addEventListener('keydown', onKeyDown);
456→        window.addEventListener('keyup', onKeyUp);
457→
458→        // Reset keys
459→        keysRef.current = { w: false, s: false, a: false, d: false, q: false, e: false };
460→        isActiveRef.current = true;
461→
462→        // Start rAF
463→        rafRef.current = requestAnimationFrame(tick);
464→    }, [tick]);
465→
466→    const exit = useCallback(() => {
467→        isActiveRef.current = false;
468→        if (rafRef.current) {
469→            cancelAnimationFrame(rafRef.current);
470→            rafRef.current = null;
471→        }
472→        // Remove key listeners
473→        if (onKeyDownRef.current) {
474→            window.removeEventListener('keydown', onKeyDownRef.current);
475→            window.removeEventListener('keyup', onKeyUpRef.current);
476→            onKeyDownRef.current = null;
477→            onKeyUpRef.current = null;
478→        }
479→        keysRef.current = { w: false, s: false, a: false, d: false, q: false, e: false };
480→        // Reset docking
481→        dockingStateRef.current = 'none';
482→        dockingTargetIdxRef.current = -1;
483→        dockingProgressRef.current = 0;
484→        dockingStarScaleRef.current = 1;
485→        inputFrozenRef.current = false;
486→        dockingCallbackRef.current = null;
487→    }, []);
488→
489→    const project = useCallback((star, cx, cy) => {
490→        if (star.viewZ <= MIN_VIEW_Z) return null; // behind camera
491→
492→        const stageWidth = stageSizeRef.current.width;
493→        const focalLength = stageWidth * 0.6; // ~80° FOV
494→        const projX = cx + (star._rotX1 / star.viewZ) * focalLength;
495→        const projY = cy - (star._rotY2 / star.viewZ) * focalLength; // negate Y for screen coords
496→        const scale = focalLength / star.viewZ;
497→
498→        return { projX, projY, scale };
499→    }, []);
500→
501→    const getTargetedPost = useCallback(() => {
502→        const idx = targetIndexRef.current;
503→        if (idx < 0 || idx >= starsRef.current.length) return null;
504→        return starsRef.current[idx].post;
505→    }, []);
506→
507→    const getSpeedRatio = useCallback(() => {
